mapper.select:
select a.pur_id ,a.pur_date+'-'+ CAST(a.seq AS NVARCHAR) AS purDateSeq ,dbo.getCustomerName(a.customer_cd) as customer_name ,CASE WHEN COUNT(b.pur_item_id) = 1 THEN MIN(b.item_name) ELSE MIN(b.item_name) + ' 외 ' + CAST(COUNT(b.pur_item_id) - 1 AS VARCHAR) + '건' END AS item_name ,sum(isnull(b.qty, 0)) as totQty ,sum(isnull(b.supply_price,0)-isnull(b.vat_price,0)) as totPrice ,dbo.getStorageName(a.storage_cd) as storage_name ,a.order_type ,dbo.getUserName(a.manager_id) as manager_name ,a.erp_yn from tb_pur_mst a inner join tb_pur_item b on a.pur_id = b.pur_id where a.pur_date between #{strDate} and #{toDate}
and a.area_cd = #{areaCd}
and b.item_cd = #{itemCd}
and b.item_name like '%' + #{itemName} + '%'
and a.end_yn = #{endYn}
and dbo.getCustomerName(a.customer_cd) like '%' + #{customerName} + '%'
group by a.pur_id, a.pur_date,a.seq, a.storage_cd, a.order_type, a.customer_cd , a.manager_id,a.erp_yn order by a.pur_date desc, a.seq desc

mapper.insert:
INSERT INTO dbo.tb_pur_mst (
    pur_date, seq, area_cd, storage_cd, customer_cd, manager_id, remark, order_type, vat_type,
    reg_id, upd_id
)
VALUES (
    #{purDate}, #{seq}, #{areaCd}, #{storageCd}, #{customerCd},#{managerId}, #{remark}, #{orderType}, #{vatType},
    #{userId}, #{userId}
       )

mapper.update:
UPDATE dbo.tb_pur_mst
SET    pur_date   = #{purDate}
      ,seq        = #{seq}
      ,area_cd    = #{areaCd}
      ,storage_cd = #{storageCd}
      ,customer_cd= #{customerCd}
      ,manager_id = #{managerId}
      ,remark     = #{remark}
      ,order_type = #{orderType}
      ,vat_type   = #{vatType}
      ,end_yn     = isnull(#{endYn}, 'N')
      ,upd_id     = #{userId}
      ,upd_dt     = GETDATE()
WHERE  pur_id     = #{purId}

update.foreach:
UPDATE  tb_pur_item
SET      pur_id       = #{item.purId}
        ,pur_order_id = #{item.purOrderId}
        ,item_cd      = #{item.itemCd}
        ,item_name    = #{item.itemName}
        ,item_type_cd = #{item.itemTypeCd}
        ,spec         = #{item.spec}
        ,qty          = #{item.qty}
        ,in_price     = #{item.inPrice}
        ,supply_price = #{item.supplyPrice}
        ,vat_price    = #{item.vatPrice}
        ,lot_no       = #{item.lotNo}
        ,test_no      = #{item.testNo}
        ,expiry_date  = #{item.expiryDate}
        ,etc          = #{item.etc}
        ,in_yn        = #{item.inYn}
        ,qc_status    = #{item.qcStatus}
        ,upd_id       = #{item.userId}
        ,upd_dt       = GETDATE()
WHERE pur_item_id  = #{item.purItemId}

mapper.select:
update tb_pur_mst
set    erp_yn ='Y'
where  pur_id = #{purId}
